const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = 'payment_events';

async function consumePaymentEvents() {
    let connection;
    let channel;

    try {
        connection = await amqp.connect(RABBITMQ_URL);
        channel = await connection.createChannel();

        await channel.assertQueue(QUEUE_NAME, {
            durable: true // Ensure the queue survives RabbitMQ restarts
        });

        // Set prefetch to 1 for fair dispatch (process one message at a time per consumer)
        channel.prefetch(1);

        console.log(`[*] Waiting for messages in ${QUEUE_NAME}. To exit press CTRL+C`);

        channel.consume(QUEUE_NAME, async (msg) => {
            if (msg !== null) {
                try {
                    const paymentEvent = JSON.parse(msg.content.toString());
                    console.log(`[x] Received payment event:`, paymentEvent);

                    // --- Payment Processing Logic ---
                    // In a real application, this would involve:
                    // 1. Validating paymentEvent structure (though trusted here, basic checks are good)
                    // 2. Interacting with a payment gateway API
                    // 3. Updating a database (e.g., marking order as paid, recording transaction)
                    // 4. Handling success/failure scenarios
                    // 5. Potentially publishing follow-up events (e.g., 'payment_successful', 'payment_failed')

                    console.log(`[+] Processing payment for order ${paymentEvent.orderId} with amount ${paymentEvent.amount} ${paymentEvent.currency}...`);

                    // Simulate a payment processing delay
                    await new Promise(resolve => setTimeout(resolve, Math.random() * 2000 + 500));

                    // Simulate success or failure based on some condition (e.g., amount)
                    if (paymentEvent.amount > 0) {
                        console.log(`[✓] Payment successful for order ${paymentEvent.orderId}. Transaction ID: ${Math.random().toString(36).substring(2, 15)}`);
                        // Acknowledge the message only after successful processing
                        channel.ack(msg);
                    } else {
                        console.error(`[✗] Payment failed for order ${paymentEvent.orderId}: Invalid amount.`);
                        // If processing fails, you might NACK the message to requeue it,
                        // or move it to a dead-letter queue depending on your error handling strategy.
                        // For simplicity, we'll just ACK it here to prevent infinite loops on bad messages.
                        channel.ack(msg); // Or channel.nack(msg, false, true); to requeue
                    }

                } catch (error) {
                    console.error(`[!] Error processing message:`, error.message);
                    console.error(`[!] Message content:`, msg.content.toString());
                    // Acknowledge the message even if parsing or processing fails
                    // to prevent it from being re-processed indefinitely if it's a malformed message.
                    // For critical errors, consider dead-lettering or manual intervention.
                    channel.ack(msg);
                }
            }
        }, {
            noAck: false // We will manually acknowledge messages
        });

    } catch (error) {
        console.error('Failed to connect or consume from RabbitMQ:', error.message);
        if (connection) {
            try {
                await connection.close();
            } catch (closeError) {
                console.error('Error closing RabbitMQ connection:', closeError.message);
            }
        }
        // Exit the process if we can't connect to RabbitMQ
        process.exit(1);
    }

    // Handle graceful shutdown
    process.on('SIGINT', async () => {
        console.log('\n[*] Shutting down consumer...');
        if (channel) {
            try {
                await channel.close();
                console.log('Channel closed.');
            } catch (e) {
                console.error('Error closing channel:', e.message);
            }
        }
        if (connection) {
            try {
                await connection.close();
                console.log('Connection closed.');
            } catch (e) {
                console.error('Error closing connection:', e.message);
            }
        }
        process.exit(0);
    });
}

consumePaymentEvents();